import json
import urllib.request
import urllib.error
import base64


def lambda_handler(event, context):
    """
    Lambda@Edge Viewer Request function that enriches requests by fetching
    additional data from URLs specified in request headers.
    
    Reads URLs from X-Enrich-URL headers (comma-separated if multiple),
    fetches data from each URL, and adds the enrichment data as additional
    headers before forwarding to origin.
    """
    request = event['Records'][0]['cf']['request']
    headers = request.get('headers', {})
    
    # Check for the X-Enrich-URL header
    enrich_header_key = 'x-enrich-url'
    
    if enrich_header_key not in headers:
        # No enrichment requested, pass through
        return request
    
    # Extract all enrichment URLs from the header(s)
    enrich_urls = []
    for header_entry in headers[enrich_header_key]:
        # Support comma-separated URLs in a single header value
        urls = [url.strip() for url in header_entry['value'].split(',')]
        enrich_urls.extend(urls)
    
    # Validate and filter URLs
    allowed_schemes = ('https://',)
    validated_urls = []
    for url in enrich_urls:
        if any(url.lower().startswith(scheme) for scheme in allowed_schemes):
            validated_urls.append(url)
    
    if not validated_urls:
        # Remove the enrichment header and pass through
        _remove_header(headers, enrich_header_key)
        return request
    
    # Fetch data from each enrichment URL
    enrichment_results = []
    max_urls = 5  # Limit to prevent excessive latency
    timeout_seconds = 2  # Short timeout for edge processing
    
    for i, url in enumerate(validated_urls[:max_urls]):
        result = _fetch_url(url, timeout_seconds)
        enrichment_results.append(result)
    
    # Add enrichment data as headers for origin consumption
    # Combine all enrichment results into a JSON structure
    enrichment_payload = {
        'enrichment_count': len(enrichment_results),
        'results': enrichment_results
    }
    
    # Serialize and encode the enrichment data
    enrichment_json = json.dumps(enrichment_payload, default=str)
    
    # Base64 encode to safely pass in HTTP header
    enrichment_encoded = base64.b64encode(enrichment_json.encode('utf-8')).decode('utf-8')
    
    # Add enrichment data header (CloudFront headers format)
    headers['x-enrichment-data'] = [{
        'key': 'X-Enrichment-Data',
        'value': enrichment_encoded
    }]
    
    # Add individual result status headers for quick inspection
    headers['x-enrichment-count'] = [{
        'key': 'X-Enrichment-Count',
        'value': str(len(enrichment_results))
    }]
    
    # Add individual enriched data headers for each source (truncated for header size limits)
    for i, result in enumerate(enrichment_results):
        if result.get('success') and result.get('body'):
            header_name = f'x-enriched-{i}'
            # Truncate body to avoid exceeding header size limits (8KB per header in CloudFront)
            truncated_body = result['body'][:6000]
            encoded_body = base64.b64encode(truncated_body.encode('utf-8')).decode('utf-8')
            headers[header_name] = [{
                'key': f'X-Enriched-{i}',
                'value': encoded_body
            }]
        
        # Add status header for each URL
        status_header_name = f'x-enriched-{i}-status'
        headers[status_header_name] = [{
            'key': f'X-Enriched-{i}-Status',
            'value': str(result.get('status_code', 'error'))
        }]
    
    # Remove the original enrichment URL header to avoid leaking internal URLs to origin
    _remove_header(headers, enrich_header_key)
    
    # Add a header indicating enrichment was performed
    headers['x-enrichment-processed'] = [{
        'key': 'X-Enrichment-Processed',
        'value': 'true'
    }]
    
    request['headers'] = headers
    return request


def _fetch_url(url, timeout_seconds=2):
    """
    Fetch data from a URL and return a structured result.
    
    Uses urllib (available in Lambda@Edge) since external packages
    like requests are not guaranteed.
    
    Args:
        url: The URL to fetch
        timeout_seconds: Request timeout in seconds
        
    Returns:
        dict with keys: url, success, status_code, body, content_type, error
    """
    result = {
        'url': url,
        'success': False,
        'status_code': None,
        'body': None,
        'content_type': None,
        'error': None
    }
    
    try:
        req = urllib.request.Request(
            url,
            method='GET',
            headers={
                'User-Agent': 'LambdaEdge-Enrichment/1.0',
                'Accept': 'application/json, text/plain, */*',
                'X-Forwarded-By': 'lambda-edge-enrichment'
            }
        )
        
        with urllib.request.urlopen(req, timeout=timeout_seconds) as response:
            result['status_code'] = response.getcode()
            result['content_type'] = response.headers.get('Content-Type', '')
            
            # Read response body with size limit (128KB max)
            max_body_size = 128 * 1024
            body_bytes = response.read(max_body_size)
            
            # Attempt to decode as UTF-8
            try:
                result['body'] = body_bytes.decode('utf-8')
            except UnicodeDecodeError:
                result['body'] = base64.b64encode(body_bytes).decode('utf-8')
            
            result['success'] = 200 <= result['status_code'] < 300
            
    except urllib.error.HTTPError as e:
        result['status_code'] = e.code
        result['error'] = f'HTTP {e.code}: {e.reason}'
        try:
            error_body = e.read(4096).decode('utf-8', errors='replace')
            result['body'] = error_body
        except Exception:
            pass
            
    except urllib.error.URLError as e:
        result['error'] = f'URL Error: {str(e.reason)}'
        
    except TimeoutError:
        result['error'] = f'Timeout after {timeout_seconds}s'
        
    except Exception as e:
        result['error'] = f'Unexpected error: {str(e)}'
    
    return result


def _remove_header(headers, header_name):
    """
    Safely remove a header from the CloudFront headers dict.
    
    Args:
        headers: CloudFront headers dictionary
        header_name: Lowercase header name to remove
    """
    if header_name in headers:
        del headers[header_name]